const items = $input.all();

return items.map((item) => {
  const payload = JSON.parse(JSON.stringify(item.json || {}));
  const address = payload.address && typeof payload.address === 'object' ? payload.address : {};
  const runtime = payload._runtime && typeof payload._runtime === 'object' ? payload._runtime : {};

  if (!payload.location_enrichment || typeof payload.location_enrichment !== 'object') {
    payload.location_enrichment = {
      latitude: null,
      longitude: null,
      aerial_image_url: null,
      location_description: null,
      public_transport_access: null,
      distance_city_center_min: null,
      distance_train_station_min: null,
      distance_airport_min: null,
      infrastructure: [],
    };
  }

  if (!payload.processing_metadata || typeof payload.processing_metadata !== 'object') {
    payload.processing_metadata = {
      document_id: null,
      source_filename: null,
      ingestion_channel: null,
      processed_at: null,
      status: null,
      validation_errors: [],
    };
  }

  if (!Array.isArray(payload.processing_metadata.validation_errors)) {
    payload.processing_metadata.validation_errors = [];
  }

  const streetLine = [address.street, address.house_number].filter(Boolean).join(' ').trim();
  const localityLine = [address.postal_code, address.city].filter(Boolean).join(' ').trim();
  const hasMeaningfulAddress = Boolean(streetLine || localityLine);
  const fullAddress = hasMeaningfulAddress
    ? [streetLine, localityLine, address.country || 'Austria'].filter(Boolean).join(', ')
    : null;

  payload._runtime = {
    ...runtime,
    enrichment_attempted: hasMeaningfulAddress,
    enrichment_failed: false,
    enrichment_errors: Array.isArray(runtime.enrichment_errors) ? runtime.enrichment_errors : [],
    infrastructure: Array.isArray(runtime.infrastructure) ? runtime.infrastructure : [],
    full_address: fullAddress,
    expose_location_description: payload.location_enrichment.location_description || null,
  };

  return { json: payload };
});

const payload = JSON.parse(JSON.stringify($('Prepare Enrichment Request').first().json || {}));
const response = $input.first()?.json || {};
const runtime = payload._runtime && typeof payload._runtime === 'object' ? payload._runtime : {};
const errors = Array.isArray(runtime.enrichment_errors) ? [...runtime.enrichment_errors] : [];

let latitude = null;
let longitude = null;

if (response.error) {
  errors.push(`geocode:${response.error.message || response.error}`);
}

if (response.status === 'OK' && Array.isArray(response.results) && response.results[0]?.geometry?.location) {
  latitude = Number(response.results[0].geometry.location.lat);
  longitude = Number(response.results[0].geometry.location.lng);
}

if ((latitude === null || Number.isNaN(latitude)) || (longitude === null || Number.isNaN(longitude))) {
  latitude = null;
  longitude = null;
  if (runtime.enrichment_attempted) {
    errors.push(`geocode_status:${response.status || 'UNAVAILABLE'}`);
  }
}

payload.location_enrichment.latitude = latitude;
payload.location_enrichment.longitude = longitude;
payload._runtime = {
  ...runtime,
  enrichment_errors: Array.from(new Set(errors)),
  geocode_status: response.status || null,
};

return [{ json: payload }];

