}

function distanceMeters(lat1, lon1, lat2, lon2) {
  var numericValues = [lat1, lon1, lat2, lon2].map(function(value) {
    return Number(value);
  });
  var distance = null;
  if (!numericValues.some(function(value) { return !Number.isFinite(value); })) {
    var toRad = function(deg) { return (deg * Math.PI) / 180; };
    var earthRadiusM = 6371000;
    var dLat = toRad(numericValues[2] - numericValues[0]);
    var dLon = toRad(numericValues[3] - numericValues[1]);
    var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) + Math.cos(toRad(numericValues[0])) * Math.cos(toRad(numericValues[2])) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
    var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    distance = Math.round(earthRadiusM * c);
  }
  return { value: distance };
}

var originLat = payload.location_enrichment ? payload.location_enrichment.latitude : null;
var originLon = payload.location_enrichment ? payload.location_enrichment.longitude : null;
var infrastructure = Array.isArray(payload._runtime?.infrastructure) ? payload._runtime.infrastructure.slice() : [];
var places = Array.isArray(response.places) ? response.places : [];
for (var index = 0; index < Math.min(places.length, 5); index += 1) {
  var place = places[index];
  infrastructure.push({
    category: 'education',
    name: place.displayName?.text || null,
    address: place.formattedAddress || null,
    distance_m: distanceMeters(originLat, originLon, place.location?.latitude, place.location?.longitude).value,
  });
}

payload._runtime = {
  ...payload._runtime,
  infrastructure,
  enrichment_errors: Array.from(new Set(errors)),
};

return [{ json: payload }];

