var inputItems = $input.all();
var firstInputJson = inputItems[0] ? (inputItems[0].json || {}) : {};

var retailItems = [];
try { retailItems = $('Process Daily Retail Infrastructure').all(); } catch (e) { /* node not executed */ }
var geocodeItems = [];
try { geocodeItems = $('Process Geocode Result').all(); } catch (e) { /* node not executed */ }

var payloadSource = firstInputJson;
if (retailItems.length) {
  payloadSource = retailItems[0].json || firstInputJson;
} else if (firstInputJson.location_enrichment && firstInputJson.processing_metadata) {
  payloadSource = firstInputJson;
} else if (geocodeItems.length) {
  payloadSource = geocodeItems[0].json || firstInputJson;
}

var payload = JSON.parse(JSON.stringify(payloadSource || {}));
var runtime = payload._runtime && typeof payload._runtime === 'object' ? payload._runtime : {};
var errors = Array.isArray(runtime.enrichment_errors) ? runtime.enrichment_errors.slice() : [];

var routeMatrixElements = [];
for (var itemIndex = 0; itemIndex < inputItems.length; itemIndex += 1) {
  var itemJson = inputItems[itemIndex] ? (inputItems[itemIndex].json || {}) : {};
  if (itemJson && itemJson.location_enrichment && itemJson.processing_metadata) {
    continue;
  }
  if (itemJson.error) {
    errors.push('route_matrix:' + (itemJson.error.message || itemJson.error));
  }
  if (itemJson.destinationIndex != null) {
    routeMatrixElements.push(itemJson);
  }
}

function durationToMinutes(value) {
  var minutes = null;
  if (typeof value === 'string') {
    var match = value.match(/^([0-9.]+)s$/);
    if (match) {
      var seconds = Number(match[1]);
      minutes = Number.isFinite(seconds) ? Math.round(seconds / 60) : null;
    }
  }
  return { value: minutes };
}

var cityMinutes = null;
var trainMinutes = null;
var airportMinutes = null;
for (var routeIndex = 0; routeIndex < routeMatrixElements.length; routeIndex += 1) {
  var element = routeMatrixElements[routeIndex];
  if (!element || element.condition !== 'ROUTE_EXISTS') {
    continue;
  }
  var minutes = durationToMinutes(element.duration).value;
  if (minutes == null) {
    continue;
  }
  if (element.destinationIndex === 0) cityMinutes = minutes;
  if (element.destinationIndex === 1) trainMinutes = minutes;
  if (element.destinationIndex === 2) airportMinutes = minutes;
}

payload.location_enrichment.distance_city_center_min = cityMinutes;
payload.location_enrichment.distance_train_station_min = trainMinutes;
payload.location_enrichment.distance_airport_min = airportMinutes;
payload.location_enrichment.aerial_image_url = null;

var infrastructure = [];
var runtimeInfrastructure = Array.isArray(runtime.infrastructure) ? runtime.infrastructure : [];
for (var infraIndex = 0; infraIndex < runtimeInfrastructure.length; infraIndex += 1) {
  var entry = runtimeInfrastructure[infraIndex];
  if (entry && (entry.name || entry.address)) infrastructure.push(entry);
}
payload.location_enrichment.infrastructure = infrastructure;

var counts = { education: 0, healthcare: 0, retail: 0, other: 0 };
for (var countIndex = 0; countIndex < infrastructure.length; countIndex += 1) {
  var infraEntry = infrastructure[countIndex];
  var category = infraEntry.category || 'other';
  if (Object.prototype.hasOwnProperty.call(counts, category)) counts[category] += 1;
  else counts.other += 1;
}

var address = payload.address && typeof payload.address === 'object' ? payload.address : {};
var generatedLocationSummary = [];
if (address.city) generatedLocationSummary.push('Micro-location in ' + address.city);
if (trainMinutes != null) generatedLocationSummary.push('nearest train station about ' + trainMinutes + ' min by public transport');
if (airportMinutes != null) generatedLocationSummary.push('airport about ' + airportMinutes + ' min by public transport');
if (counts.education) generatedLocationSummary.push(String(counts.education) + ' education POIs found nearby');
if (counts.healthcare) generatedLocationSummary.push(String(counts.healthcare) + ' healthcare POIs found nearby');
if (counts.retail) generatedLocationSummary.push(String(counts.retail) + ' retail POIs found nearby');
if (runtime.expose_location_description) payload.location_enrichment.location_description = runtime.expose_location_description;
else if (generatedLocationSummary.length) payload.location_enrichment.location_description = generatedLocationSummary.join('; ');
else payload.location_enrichment.location_description = null;

var publicTransportSummary = [];
if (cityMinutes != null) publicTransportSummary.push('city center about ' + cityMinutes + ' min');
if (trainMinutes != null) publicTransportSummary.push('train station about ' + trainMinutes + ' min');
if (airportMinutes != null) publicTransportSummary.push('airport about ' + airportMinutes + ' min');
payload.location_enrichment.public_transport_access = publicTransportSummary.length ? publicTransportSummary.join('; ') : null;

payload._runtime = {
  ...runtime,
  enrichment_errors: Array.from(new Set(errors)),
  enrichment_failed: Boolean(runtime.enrichment_attempted && (payload.location_enrichment.latitude == null || payload.location_enrichment.longitude == null || errors.length > 0))
};

return [{ json: payload }];
